import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  price: number;
  category: 'Hoodie' | 'T-Shirt' | 'Accessories' | 'Footwear';
  image: string;
  description: string;
  color: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getStylingAdvice(history: ChatMessage[], userPrompt: string) {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are the WADIDAW AI Stylist. WADIDAW is a futuristic, streetwear-focused fashion brand.
        Your tone is cool, trendy, and helpful. You should suggest outfits based on the user's mood, the weather, or specific occasions.
        Keep your answers concise and energetic. Refer to WADIDAW products like "Neon Hoodie", "Orbit Sneakers", and "Cyberpunk Tee".
        Avoid overly formal language. Use emojis related to fashion.`,
      },
    });

    // We don't need to pass the whole history to sendMessage if we use the chat object, 
    // but the API wrapper for sendMessage typically handles the message only.
    const response = await chat.sendMessage({ message: userPrompt });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Wadidaw! I'm having a small glitch in my fashion matrix. Try again in a second!";
  }
}

import React, { useRef, Suspense } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sphere, MeshDistortMaterial, Float, PerspectiveCamera, Stars } from '@react-three/drei';
import * as THREE from 'three';

const AnimatedShape = () => {
  const meshRef = useRef<THREE.Mesh>(null!);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    meshRef.current.rotation.x = Math.sin(time / 4);
    meshRef.current.rotation.y = Math.cos(time / 2);
  });

  return (
    <Float speed={2} rotationIntensity={1.5} floatIntensity={2}>
      <Sphere ref={meshRef} args={[1, 100, 100]} scale={1.5}>
        <MeshDistortMaterial
          color="#1e1e1e"
          attach="material"
          distort={0.4}
          speed={4}
          roughness={0.1}
          metalness={0.9}
        />
      </Sphere>
    </Float>
  );
};

const LightRing = ({ color, position, rotation }: { color: string, position: [number, number, number], rotation: [number, number, number] }) => {
  return (
    <mesh position={position} rotation={rotation}>
      <torusGeometry args={[2.5, 0.02, 16, 100]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={5} />
    </mesh>
  );
};

const Hero3D: React.FC = () => {
  return (
    <div className="absolute inset-0 z-0 h-screen w-full">
      <Canvas shadows dpr={[1, 2]}>
        <PerspectiveCamera makeDefault position={[0, 0, 8]} fov={45} />
        <OrbitControls enableZoom={false} autoRotate autoRotateSpeed={0.5} />

        <ambientLight intensity={0.5} />
        <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={1} castShadow />
        <pointLight position={[-10, -10, -10]} intensity={0.5} color="#00f2ff" />
        <pointLight position={[10, 5, 5]} intensity={0.5} color="#ff00ff" />

        <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

        <Suspense fallback={null}>
          <AnimatedShape />
          <LightRing color="#00f2ff" position={[0, 0, 0]} rotation={[Math.PI / 2, 0, 0]} />
          <LightRing color="#ff00ff" position={[0, 0, 0]} rotation={[0, Math.PI / 2, 0]} />
        </Suspense>
      </Canvas>
    </div>
  );
};

export default Hero3D;

