<p>Generate content with multiple parts, for example, by sending an image and a text prompt to the model.</p>
<pre><code class="language-ts">import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
